// server.js
export async function init(ctx) {
  ctx.router.get('/stats', async (req, res) => {
    const [rows] = await ctx.db.execute(
      'SELECT COUNT(*) as total FROM orders WHERE store_id = ?',
      [req.query.store_id]
    );
    res.json({ total_orders: rows[0].total });
  });
}

